// Convert each node into chunk
const workflow = $input.first().json;
const allChunks = [];

if (workflow.nodes && workflow.nodes.length > 0) {
  for (const node of workflow.nodes) {
    allChunks.push({
      content: `Workflow: "${workflow.name}" (ID: ${workflow.id}). Node Name: "${node.name}". Type: "${node.type}". Logic: ${JSON.stringify(node.parameters)}`,
      metadata: {
        workflowId: workflow.id,
        nodeType: node.type,
        nodeName: node.name
      }
    });
  }
  return allChunks;
} else {
  return [{
    content: "Empty Workflow",
    metadata: { workflowId: workflow.id }
  }];
}
